import Vue from 'vue'
import Vuex from 'vuex'
import api from '../services/api'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    user: JSON.parse(localStorage.getItem('ticket_user')) || null,
    tickets: [],
    areas: [],
    subjects: [],
    users: [],
    loading: false
  },
  getters: {
    isAdmin: state => state.user?.role === 'Administrador',
    isGestor: state => state.user?.role === 'Gestionador',
    availableTickets: state => state.tickets
  },
  mutations: {
    SET_USER(state, user) {
      state.user = user;
      if (user) localStorage.setItem('ticket_user', JSON.stringify(user));
      else localStorage.removeItem('ticket_user');
    },
    SET_TICKETS(state, tickets) {
      state.tickets = tickets;
    },
    SET_AREAS(state, areas) {
      state.areas = areas;
    },
    SET_SUBJECTS(state, subjects) {
      state.subjects = subjects;
    },
    SET_USERS(state, users) {
      state.users = users;
    },
    SET_LOADING(state, val) {
      state.loading = val;
    },
    ADD_TICKET(state, ticket) {
      state.tickets.unshift(ticket);
    },
    UPDATE_TICKET(state, updatedTicket) {
      const index = state.tickets.findIndex(t => t.id === updatedTicket.id);
      if (index !== -1) {
        Vue.set(state.tickets, index, updatedTicket);
      }
    }
  },
  actions: {
    // ---- AUTH ----
    async login({ commit, dispatch }, email) {
      const res = await api.post('/auth/login', { email });
      const { jwt, user } = res.data;
      localStorage.setItem('jwt_token', jwt);
      commit('SET_USER', user);
      // Cargar datos iniciales después del login
      await dispatch('loadInitialData');
      return user;
    },

    logout({ commit }) {
      localStorage.removeItem('jwt_token');
      commit('SET_USER', null);
      commit('SET_TICKETS', []);
      commit('SET_AREAS', []);
      commit('SET_SUBJECTS', []);
    },

    // ---- CARGA INICIAL ----
    async loadInitialData({ dispatch }) {
      await Promise.all([
        dispatch('fetchAreas'),
        dispatch('fetchSubjects'),
        dispatch('fetchTickets')
      ]);
    },

    // ---- ÁREAS ----
    async fetchAreas({ commit }) {
      try {
        const res = await api.get('/areas');
        commit('SET_AREAS', res.data);
      } catch (e) {
        console.error('Error cargando áreas:', e);
      }
    },

    // ---- ASUNTOS ----
    async fetchSubjects({ commit }) {
      try {
        const res = await api.get('/subjects');
        commit('SET_SUBJECTS', res.data);
      } catch (e) {
        console.error('Error cargando asuntos:', e);
      }
    },

    // ---- TICKETS ----
    async fetchTickets({ commit }) {
      try {
        commit('SET_LOADING', true);
        const res = await api.get('/tickets');
        // Spring Page tiene .content para los elementos
        const tickets = res.data.content || res.data;
        commit('SET_TICKETS', tickets);
      } catch (e) {
        console.error('Error cargando tickets:', e);
      } finally {
        commit('SET_LOADING', false);
      }
    },

    async createTicket({ commit }, payload) {
      const res = await api.post('/tickets', payload);
      const ticket = res.data;
      commit('ADD_TICKET', ticket);
      return ticket;
    },

    async changeTicketStatus({ commit }, { ticketId, status }) {
      const res = await api.patch(`/tickets/${ticketId}/status`, { status });
      const ticket = res.data;
      commit('UPDATE_TICKET', ticket);
      return ticket;
    },

    // ---- USUARIOS (Admin) ----
    async fetchUsers({ commit }) {
      try {
        const res = await api.get('/users');
        commit('SET_USERS', res.data);
      } catch (e) {
        console.error('Error cargando usuarios:', e);
      }
    },

    // ---- CONFIG (Admin) ----
    async createArea({ dispatch }, nombre) {
      await api.post('/areas', { nombre });
      await dispatch('fetchAreas');
    },

    async deleteArea({ dispatch }, id) {
      await api.delete(`/areas/${id}`);
      await dispatch('fetchAreas');
    },

    async createSubject({ dispatch }, data) {
      await api.post('/subjects', data);
      await dispatch('fetchSubjects');
    },

    async deleteSubject({ dispatch }, id) {
      await api.delete(`/subjects/${id}`);
      await dispatch('fetchSubjects');
    }
  }
})
